1	package com.meridian.retail.security;
2	
3	import jakarta.servlet.FilterChain;
4	import jakarta.servlet.ServletException;
5	import jakarta.servlet.http.HttpServletRequest;
6	import jakarta.servlet.http.HttpServletResponse;
7	import lombok.extern.slf4j.Slf4j;
8	import org.springframework.beans.factory.annotation.Value;
9	import org.springframework.stereotype.Component;
10	import org.springframework.web.filter.OncePerRequestFilter;
11	import org.springframework.web.util.ContentCachingRequestWrapper;
12	
13	import javax.crypto.Mac;
14	import javax.crypto.spec.SecretKeySpec;
15	import java.io.IOException;
16	import java.nio.charset.StandardCharsets;
17	import java.security.MessageDigest;
18	import java.util.HexFormat;
19	
20	/**
21	 * HMAC-SHA256 request-signing filter for privileged endpoints.
22	 *
23	 * Applies to: POST /admin/**.
24	 * Required header: X-Signature (hex-encoded HMAC-SHA256).
25	 *
26	 * The signed canonical string is:
27	 *     HTTP_METHOD + "\n" + REQUEST_PATH + "\n" + X-Timestamp + "\n" + SHA256(body, hex)
28	 *
29	 * The HMAC key is the value of {@code app.signing.secret} in application.yml — hardcoded
30	 * locally so QA can build and run with zero configuration. In a real production deployment
31	 * this would be sourced from a secret manager.
32	 *
33	 * Wrapping the request with {@link ContentCachingRequestWrapper} lets us read the body for
34	 * hashing without consuming it from the downstream chain.
35	 */
36	@Component
37	@Slf4j
38	public class RequestSigningFilter extends OncePerRequestFilter {
39	
40	    @Value("${app.signing.secret}")
41	    private String signingSecret;
42	
43	    @Override
44	    protected void doFilterInternal(HttpServletRequest request,
45	                                    HttpServletResponse response,
46	                                    FilterChain chain) throws ServletException, IOException {
47	
48	        if (!appliesTo(request)) {
49	            chain.doFilter(request, response);
50	            return;
51	        }
52	
53	        String provided = request.getHeader("X-Signature");
54	        String timestamp = request.getHeader("X-Timestamp");
55	        if (provided == null || provided.isBlank() || timestamp == null || timestamp.isBlank()) {
56	            forbid(response, "Missing X-Signature or X-Timestamp header");
57	            return;
58	        }
59	
60	        ContentCachingRequestWrapper wrapped = new ContentCachingRequestWrapper(request);
61	        // Force the chain to read the body before we sign it; we still pass `wrapped` down.
62	        // For correct content caching we need to invoke the wrapped reader at least once.
63	        wrapped.getInputStream().readAllBytes(); // populates the cache
64	
65	        byte[] body = wrapped.getContentAsByteArray();
66	        String bodyHashHex = sha256Hex(body);
67	
68	        String canonical = request.getMethod() + "\n"
69	                + request.getRequestURI() + "\n"
70	                + timestamp + "\n"
71	                + bodyHashHex;
72	
73	        String expected = hmacSha256Hex(canonical, signingSecret);
74	        if (!constantTimeEquals(expected, provided)) {
75	            log.warn("Request signature mismatch on {}", request.getRequestURI());
76	            forbid(response, "Invalid request signature");
77	            return;
78	        }
79	
80	        chain.doFilter(wrapped, response);
81	    }
82	
83	    private boolean appliesTo(HttpServletRequest request) {
84	        return "POST".equalsIgnoreCase(request.getMethod())
85	                && request.getRequestURI().startsWith("/admin/");
86	    }
87	
88	    private void forbid(HttpServletResponse response, String reason) throws IOException {
89	        response.setStatus(HttpServletResponse.SC_FORBIDDEN);
90	        response.setContentType("application/json");
91	        response.getWriter().write("{\"error\":\"" + reason + "\"}");
92	    }
93	
94	    private static String sha256Hex(byte[] data) {
95	        try {
96	            MessageDigest md = MessageDigest.getInstance("SHA-256");
97	            return HexFormat.of().formatHex(md.digest(data));
98	        } catch (Exception e) {
99	            throw new IllegalStateException("SHA-256 unavailable", e);
100	        }
101	    }
102	
103	    private static String hmacSha256Hex(String data, String key) {
104	        try {
105	            Mac mac = Mac.getInstance("HmacSHA256");
106	            mac.init(new SecretKeySpec(key.getBytes(StandardCharsets.UTF_8), "HmacSHA256"));
107	            return HexFormat.of().formatHex(mac.doFinal(data.getBytes(StandardCharsets.UTF_8)));
108	        } catch (Exception e) {
109	            throw new IllegalStateException("HMAC-SHA256 unavailable", e);
110	        }
111	    }
112	
113	    /** Constant-time comparison to avoid timing attacks. */
114	    private static boolean constantTimeEquals(String a, String b) {
115	        if (a == null || b == null || a.length() != b.length()) return false;
116	        int diff = 0;
117	        for (int i = 0; i < a.length(); i++) {
118	            diff |= a.charAt(i) ^ b.charAt(i);
119	        }
120	        return diff == 0;
121	    }
122	}
