1	package com.meridian.retail.controller;
2	
3	import com.meridian.retail.service.ApprovalService;
4	import com.meridian.retail.service.CampaignValidationException;
5	import com.meridian.retail.service.DualApprovalService;
6	import com.meridian.retail.service.SameApproverException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import lombok.RequiredArgsConstructor;
9	import org.springframework.security.access.prepost.PreAuthorize;
10	import org.springframework.security.core.Authentication;
11	import org.springframework.stereotype.Controller;
12	import org.springframework.ui.Model;
13	import org.springframework.web.bind.annotation.*;
14	import org.springframework.web.servlet.mvc.support.RedirectAttributes;
15	
16	@Controller
17	@RequestMapping("/approval")
18	@RequiredArgsConstructor
19	@PreAuthorize("hasAnyRole('REVIEWER','ADMIN')")
20	public class ApprovalController {
21	
22	    private final ApprovalService approvalService;
23	    private final DualApprovalService dualApprovalService;
24	
25	    @GetMapping("/queue")
26	    public String queue(Model model) {
27	        model.addAttribute("breadcrumb", "Approval Queue");
28	        model.addAttribute("queueItems", approvalService.listPending());
29	        return "approval/queue";
30	    }
31	
32	    @PostMapping("/{id}/approve")
33	    public String approve(@PathVariable Long id,
34	                          @RequestParam(required = false) String notes,
35	                          Authentication authentication,
36	                          HttpServletRequest httpRequest,
37	                          RedirectAttributes redirect) {
38	        try {
39	            approvalService.approve(id, authentication.getName(), notes, clientIp(httpRequest));
40	            redirect.addFlashAttribute("successMessage", "Approval recorded.");
41	        } catch (SameApproverException | CampaignValidationException e) {
42	            redirect.addFlashAttribute("errorMessage", e.getMessage());
43	        }
44	        return "redirect:/approval/queue";
45	    }
46	
47	    @PostMapping("/{id}/reject")
48	    public String reject(@PathVariable Long id,
49	                         @RequestParam(required = false) String notes,
50	                         Authentication authentication,
51	                         HttpServletRequest httpRequest,
52	                         RedirectAttributes redirect) {
53	        try {
54	            approvalService.reject(id, authentication.getName(), notes, clientIp(httpRequest));
55	            redirect.addFlashAttribute("successMessage", "Rejection recorded.");
56	        } catch (SameApproverException | CampaignValidationException e) {
57	            redirect.addFlashAttribute("errorMessage", e.getMessage());
58	        }
59	        return "redirect:/approval/queue";
60	    }
61	
62	    /**
63	     * Dual-approval second step. The NonceValidationFilter intercepts this URL and
64	     * requires X-Nonce + X-Timestamp headers (anti-replay).
65	     */
66	    @PostMapping("/dual-approve/{requestId}")
67	    public String dualApprove(@PathVariable Long requestId,
68	                              Authentication authentication,
69	                              HttpServletRequest httpRequest,
70	                              RedirectAttributes redirect) {
71	        try {
72	            dualApprovalService.recordSecond(requestId, authentication.getName(), clientIp(httpRequest));
73	            redirect.addFlashAttribute("successMessage", "Dual approval complete.");
74	        } catch (SameApproverException | CampaignValidationException e) {
75	            redirect.addFlashAttribute("errorMessage", e.getMessage());
76	        }
77	        return "redirect:/approval/queue";
78	    }
79	
80	    private String clientIp(HttpServletRequest request) {
81	        String header = request.getHeader("X-Forwarded-For");
82	        if (header != null && !header.isBlank()) return header.split(",")[0].trim();
83	        return request.getRemoteAddr();
84	    }
85	}
