1	package com.meridian.retail.service;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.entity.DualApprovalRequest;
6	import com.meridian.retail.entity.DualApprovalStatus;
7	import com.meridian.retail.repository.DualApprovalRequestRepository;
8	import lombok.RequiredArgsConstructor;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import java.time.LocalDateTime;
13	
14	/**
15	 * Two-eyes approval workflow for HIGH-risk campaigns and permission changes.
16	 *
17	 * Rule: approver1 != approver2 (enforced when recordSecond is called).
18	 * If the same user attempts to be both approvers a SameApproverException is raised
19	 * — the service NEVER persists the second approval in that case.
20	 */
21	@Service
22	@RequiredArgsConstructor
23	public class DualApprovalService {
24	
25	    private final DualApprovalRequestRepository repository;
26	    private final AuditLogService auditLogService;
27	
28	    @Transactional
29	    public DualApprovalRequest initiate(Long approvalQueueId) {
30	        // If a request already exists for this queue entry, reuse it.
31	        return repository.findByApprovalQueueId(approvalQueueId).orElseGet(() ->
32	                repository.save(DualApprovalRequest.builder()
33	                        .approvalQueueId(approvalQueueId)
34	                        .status(DualApprovalStatus.PENDING)
35	                        .build())
36	        );
37	    }
38	
39	    @Transactional
40	    public DualApprovalRequest recordFirst(Long requestId, String approverUsername, String ipAddress) {
41	        DualApprovalRequest req = repository.findById(requestId)
42	                .orElseThrow(() -> new CampaignValidationException("Dual approval request not found: " + requestId));
43	        if (req.getStatus() == DualApprovalStatus.COMPLETE) {
44	            throw new CampaignValidationException("Dual approval already complete");
45	        }
46	        req.setApprover1Username(approverUsername);
47	        req.setApprover1At(LocalDateTime.now());
48	        DualApprovalRequest saved = repository.save(req);
49	        auditLogService.log(AuditAction.DUAL_APPROVAL_FIRST, "DualApprovalRequest", saved.getId(),
50	                null, saved, approverUsername, ipAddress);
51	        return saved;
52	    }
53	
54	    @Transactional
55	    public DualApprovalRequest recordSecond(Long requestId, String approverUsername, String ipAddress) {
56	        DualApprovalRequest req = repository.findById(requestId)
57	                .orElseThrow(() -> new CampaignValidationException("Dual approval request not found: " + requestId));
58	        if (req.getApprover1Username() == null) {
59	            throw new CampaignValidationException("First approver not yet recorded");
60	        }
61	        if (req.getApprover1Username().equalsIgnoreCase(approverUsername)) {
62	            // Two-eyes principle: same person cannot fulfil both halves.
63	            throw new SameApproverException("Approver1 and approver2 must be different users");
64	        }
65	        req.setApprover2Username(approverUsername);
66	        req.setApprover2At(LocalDateTime.now());
67	        req.setStatus(DualApprovalStatus.COMPLETE);
68	        DualApprovalRequest saved = repository.save(req);
69	        auditLogService.log(AuditAction.DUAL_APPROVAL_SECOND, "DualApprovalRequest", saved.getId(),
70	                null, saved, approverUsername, ipAddress);
71	        return saved;
72	    }
73	
74	    public boolean isComplete(Long requestId) {
75	        return repository.findById(requestId)
76	                .map(r -> r.getStatus() == DualApprovalStatus.COMPLETE)
77	                .orElse(false);
78	    }
79	}
