1	package com.meridian.retail.service;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.entity.ApprovalQueue;
6	import com.meridian.retail.entity.ApprovalStatus;
7	import com.meridian.retail.entity.Campaign;
8	import com.meridian.retail.entity.CampaignStatus;
9	import com.meridian.retail.entity.RiskLevel;
10	import com.meridian.retail.repository.ApprovalQueueRepository;
11	import com.meridian.retail.repository.CampaignRepository;
12	import com.meridian.retail.security.XssInputSanitizer;
13	import lombok.RequiredArgsConstructor;
14	import lombok.extern.slf4j.Slf4j;
15	import org.springframework.stereotype.Service;
16	import org.springframework.transaction.annotation.Transactional;
17	
18	import java.util.List;
19	
20	/**
21	 * Approval queue lifecycle: submit -> assign -> approve|reject. HIGH risk items
22	 * require two-eyes via DualApprovalService — see {@link #approve(Long, String, String, String)}.
23	 */
24	@Service
25	@RequiredArgsConstructor
26	@Slf4j
27	public class ApprovalService {
28	
29	    private final ApprovalQueueRepository approvalQueueRepository;
30	    private final CampaignRepository campaignRepository;
31	    private final DualApprovalService dualApprovalService;
32	    private final AuditLogService auditLogService;
33	
34	    public List<ApprovalQueue> listPending() {
35	        return approvalQueueRepository.findByStatusOrderByCreatedAtAsc(ApprovalStatus.PENDING);
36	    }
37	
38	    public ApprovalQueue findById(Long id) {
39	        return approvalQueueRepository.findById(id)
40	                .orElseThrow(() -> new CampaignValidationException("Approval queue entry not found: " + id));
41	    }
42	
43	    @Transactional
44	    public ApprovalQueue submitToQueue(Long campaignId, String requestedBy, RiskLevel riskLevel, String ipAddress) {
45	        Campaign c = campaignRepository.findById(campaignId)
46	                .orElseThrow(() -> new CampaignValidationException("Campaign not found: " + campaignId));
47	        ApprovalQueue q = ApprovalQueue.builder()
48	                .campaignId(c.getId())
49	                .requestedBy(requestedBy)
50	                .status(riskLevel == RiskLevel.HIGH ? ApprovalStatus.REQUIRES_DUAL : ApprovalStatus.PENDING)
51	                .riskLevel(riskLevel)
52	                .build();
53	        ApprovalQueue saved = approvalQueueRepository.save(q);
54	        if (riskLevel == RiskLevel.HIGH) {
55	            dualApprovalService.initiate(saved.getId());
56	        }
57	        auditLogService.log(AuditAction.APPROVAL_SUBMITTED, "ApprovalQueue", saved.getId(),
58	                null, saved, requestedBy, ipAddress);
59	        return saved;
60	    }
61	
62	    @Transactional
63	    public ApprovalQueue assign(Long queueId, String reviewerUsername) {
64	        ApprovalQueue q = findById(queueId);
65	        q.setAssignedReviewer(reviewerUsername);
66	        return approvalQueueRepository.save(q);
67	    }
68	
69	    /**
70	     * Approve a pending entry.
71	     *
72	     * Object-level rule: a reviewer cannot approve their own submission. We compare
73	     * requestedBy vs reviewerUsername case-insensitively and throw SameApproverException
74	     * if they match. This is enforced HERE in the service, not in the controller, so the
75	     * rule is honoured no matter what UI calls this method.
76	     */
77	    @Transactional
78	    public ApprovalQueue approve(Long queueId, String reviewerUsername, String notes, String ipAddress) {
79	        ApprovalQueue q = findById(queueId);
80	
81	        if (q.getRequestedBy() != null && q.getRequestedBy().equalsIgnoreCase(reviewerUsername)) {
82	            throw new SameApproverException("A reviewer cannot approve a campaign they themselves submitted");
83	        }
84	
85	        if (q.getRiskLevel() == RiskLevel.HIGH) {
86	            // For HIGH risk we require dual approval to be COMPLETE before flipping the status.
87	            boolean ready = dualApprovalService.isComplete(
88	                    dualApprovalService.initiate(q.getId()).getId()
89	            );
90	            if (!ready) {
91	                log.info("HIGH risk approval still requires dual sign-off: queueId={}", queueId);
92	                q.setStatus(ApprovalStatus.REQUIRES_DUAL);
93	                q.setNotes(XssInputSanitizer.sanitize(notes));
94	                q.setAssignedReviewer(reviewerUsername);
95	                approvalQueueRepository.save(q);
96	                return q;
97	            }
98	        }
99	
100	        q.setStatus(ApprovalStatus.APPROVED);
101	        q.setNotes(XssInputSanitizer.sanitize(notes));
102	        q.setAssignedReviewer(reviewerUsername);
103	        ApprovalQueue saved = approvalQueueRepository.save(q);
104	
105	        // Cascade: bump the campaign's status to APPROVED so it can later be published.
106	        campaignRepository.findById(q.getCampaignId()).ifPresent(c -> {
107	            c.setStatus(CampaignStatus.APPROVED);
108	            campaignRepository.save(c);
109	        });
110	
111	        auditLogService.log(AuditAction.APPROVAL_APPROVED, "ApprovalQueue", saved.getId(),
112	                null, saved, reviewerUsername, ipAddress);
113	        return saved;
114	    }
115	
116	    @Transactional
117	    public ApprovalQueue reject(Long queueId, String reviewerUsername, String notes, String ipAddress) {
118	        ApprovalQueue q = findById(queueId);
119	
120	        if (q.getRequestedBy() != null && q.getRequestedBy().equalsIgnoreCase(reviewerUsername)) {
121	            throw new SameApproverException("A reviewer cannot reject a campaign they themselves submitted");
122	        }
123	
124	        q.setStatus(ApprovalStatus.REJECTED);
125	        q.setNotes(XssInputSanitizer.sanitize(notes));
126	        q.setAssignedReviewer(reviewerUsername);
127	        ApprovalQueue saved = approvalQueueRepository.save(q);
128	
129	        campaignRepository.findById(q.getCampaignId()).ifPresent(c -> {
130	            c.setStatus(CampaignStatus.REJECTED);
131	            campaignRepository.save(c);
132	        });
133	
134	        auditLogService.log(AuditAction.APPROVAL_REJECTED, "ApprovalQueue", saved.getId(),
135	                null, saved, reviewerUsername, ipAddress);
136	        return saved;
137	    }
138	}
