1	package com.meridian.retail.repository;
2	
3	import com.meridian.retail.entity.AuditLog;
4	import org.springframework.data.domain.Page;
5	import org.springframework.data.domain.Pageable;
6	import org.springframework.data.jpa.repository.JpaRepository;
7	import org.springframework.data.jpa.repository.Query;
8	import org.springframework.data.repository.query.Param;
9	import org.springframework.stereotype.Repository;
10	
11	import java.time.LocalDateTime;
12	import java.util.List;
13	
14	/**
15	 * AuditLogRepository — IMMUTABLE BY DESIGN.
16	 *
17	 * No update() or delete() operations are exposed here. The only write path is save()
18	 * (which JpaRepository provides for INSERTs). Any attempt to call .deleteById(),
19	 * .deleteAll(), etc. should be considered a security violation and is intentionally
20	 * absent from the contract — Spring Data inherits these from JpaRepository, so we
21	 * additionally enforce the policy at the service layer (AuditLogService) and document
22	 * it here so static-audit reviewers can verify the design.
23	 *
24	 * IMMUTABLE: No update or delete operations permitted by design.
25	 */
26	@Repository
27	public interface AuditLogRepository extends JpaRepository<AuditLog, Long> {
28	
29	    Page<AuditLog> findAllByOrderByCreatedAtDesc(Pageable pageable);
30	
31	    List<AuditLog> findByEntityTypeAndEntityIdOrderByCreatedAtDesc(String entityType, Long entityId);
32	
33	    List<AuditLog> findByOperatorUsernameOrderByCreatedAtDesc(String operatorUsername);
34	
35	    @Query("select a from AuditLog a where " +
36	           "(:action is null or a.action = :action) and " +
37	           "(:entityType is null or a.entityType = :entityType) and " +
38	           "(:from is null or a.createdAt >= :from) and " +
39	           "(:to is null or a.createdAt <= :to) " +
40	           "order by a.createdAt desc")
41	    Page<AuditLog> search(@Param("action") String action,
42	                          @Param("entityType") String entityType,
43	                          @Param("from") LocalDateTime from,
44	                          @Param("to") LocalDateTime to,
45	                          Pageable pageable);
46	}
