1	package com.meridian.retail.config;
2	
3	import com.meridian.retail.security.CustomAuthenticationFailureHandler;
4	import com.meridian.retail.security.CustomAuthenticationSuccessHandler;
5	import com.meridian.retail.security.NonceValidationFilter;
6	import com.meridian.retail.security.RateLimitFilter;
7	import com.meridian.retail.security.RequestSigningFilter;
8	import com.meridian.retail.security.UserDetailsServiceImpl;
9	import lombok.RequiredArgsConstructor;
10	import org.springframework.context.annotation.Bean;
11	import org.springframework.context.annotation.Configuration;
12	import org.springframework.security.authentication.AuthenticationManager;
13	import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
14	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
15	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
16	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
17	import org.springframework.security.config.http.SessionCreationPolicy;
18	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
19	import org.springframework.security.crypto.password.PasswordEncoder;
20	import org.springframework.security.web.SecurityFilterChain;
21	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
22	import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
23	
24	/**
25	 * Spring Security configuration.
26	 *
27	 * Form-login (local username/password only — SPEC.md). All POST forms are CSRF-protected
28	 * via Spring Security's standard mechanism. Three custom filters are inserted BEFORE
29	 * UsernamePasswordAuthenticationFilter:
30	 *
31	 *   1. RateLimitFilter        — 60/min standard, 10/min export, per authenticated user
32	 *   2. NonceValidationFilter  — anti-replay for /admin/** and /approval/dual-approve/**
33	 *   3. RequestSigningFilter   — HMAC-SHA256 signature check for /admin/**
34	 *
35	 * Permit-all is intentionally narrow: only the login page, the locally-rendered CAPTCHA
36	 * image endpoint, the /actuator/health probe, and bundled vendor static assets.
37	 *
38	 * BCryptPasswordEncoder strength=12 matches the seed-data hashes in V12__seed_data.sql.
39	 */
40	@Configuration
41	@EnableWebSecurity
42	@EnableMethodSecurity
43	@RequiredArgsConstructor
44	public class SecurityConfig {
45	
46	    private final UserDetailsServiceImpl userDetailsService;
47	    private final CustomAuthenticationFailureHandler failureHandler;
48	    private final CustomAuthenticationSuccessHandler successHandler;
49	    private final RateLimitFilter rateLimitFilter;
50	    private final NonceValidationFilter nonceValidationFilter;
51	    private final RequestSigningFilter requestSigningFilter;
52	
53	    @Bean
54	    public PasswordEncoder passwordEncoder() {
55	        // strength = 12 matches the seed-data hashes; do not lower without re-seeding.
56	        return new BCryptPasswordEncoder(12);
57	    }
58	
59	    @Bean
60	    public AuthenticationManager authenticationManager(HttpSecurity http) throws Exception {
61	        AuthenticationManagerBuilder b = http.getSharedObject(AuthenticationManagerBuilder.class);
62	        b.userDetailsService(userDetailsService).passwordEncoder(passwordEncoder());
63	        return b.build();
64	    }
65	
66	    @Bean
67	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
68	        http
69	            .csrf(csrf -> csrf
70	                // CSRF cookie is readable by JS so HTMX can include the token header.
71	                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
72	            )
73	            .authorizeHttpRequests(auth -> auth
74	                // Public surface — kept intentionally minimal.
75	                .requestMatchers("/login", "/captcha/**", "/health", "/actuator/health",
76	                                 "/css/**", "/js/**", "/vendor/**", "/error/**").permitAll()
77	                // Role-restricted areas.
78	                .requestMatchers("/admin/**").hasRole("ADMIN")
79	                .requestMatchers("/approval/**").hasAnyRole("ADMIN", "REVIEWER")
80	                .requestMatchers("/analytics/export/**").hasAnyRole("ADMIN", "FINANCE")
81	                .anyRequest().authenticated()
82	            )
83	            .formLogin(form -> form
84	                .loginPage("/login")
85	                .loginProcessingUrl("/login")
86	                .successHandler(successHandler)
87	                .failureHandler(failureHandler)
88	                .permitAll()
89	            )
90	            .logout(logout -> logout
91	                .logoutUrl("/logout")
92	                .logoutSuccessUrl("/login?logout")
93	                .invalidateHttpSession(true)
94	                .deleteCookies("JSESSIONID", "XSRF-TOKEN")
95	                .permitAll()
96	            )
97	            .sessionManagement(session -> session
98	                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
99	                .maximumSessions(3)   // allow a few concurrent sessions per user
100	            )
101	            // No explicit accessDeniedPage. Spring Security's default access-denied handler
102	            // sets HTTP 403 and forwards to /error, where Spring Boot's BasicErrorController
103	            // automatically selects templates/error/403.html based on the status code.
104	            // (accessDeniedPage("/error/403") was removed because it does a literal URL
105	            // forward — and there is no controller mapping for /error/403, so the dispatch
106	            // would fall through to the static-resource handler and return a confusing 404.)
107	            ;
108	
109	        // Custom filters in order. Rate limit runs first so an attacker hammering /login
110	        // gets throttled before any heavy work; nonce validation runs before signing so
111	        // we don't waste time computing HMAC for replays.
112	        http.addFilterBefore(rateLimitFilter, UsernamePasswordAuthenticationFilter.class);
113	        http.addFilterBefore(nonceValidationFilter, UsernamePasswordAuthenticationFilter.class);
114	        http.addFilterBefore(requestSigningFilter, UsernamePasswordAuthenticationFilter.class);
115	
116	        return http.build();
117	    }
118	}
