1	package com.meridian.retail.security;
2	
3	import jakarta.servlet.ServletException;
4	import jakarta.servlet.http.HttpServletRequest;
5	import jakarta.servlet.http.HttpServletResponse;
6	import jakarta.servlet.http.HttpSession;
7	import lombok.RequiredArgsConstructor;
8	import lombok.extern.slf4j.Slf4j;
9	import org.springframework.beans.factory.annotation.Value;
10	import org.springframework.security.core.AuthenticationException;
11	import org.springframework.security.web.authentication.SimpleUrlAuthenticationFailureHandler;
12	import org.springframework.stereotype.Component;
13	
14	import java.io.IOException;
15	
16	/**
17	 * Authentication failure handler.
18	 *
19	 * Responsibilities (in order):
20	 *   1. Track the failed attempt against the username + client IP (account/IP lockout state).
21	 *   2. Validate the locally-rendered CAPTCHA if the session indicates one was required
22	 *      (i.e. there have already been >= captchaThreshold failures for this account).
23	 *   3. Decide which redirect to issue:
24	 *        - /login?ipblocked  if this IP has now exceeded its hourly threshold
25	 *        - /login?locked     if this account is now locked
26	 *        - /login?error      otherwise (generic "wrong credentials")
27	 *   4. Set the session "captchaRequired" attribute if the failure count is at or above
28	 *      the captcha threshold so the next login form render shows the CAPTCHA challenge.
29	 */
30	@Component
31	@RequiredArgsConstructor
32	@Slf4j
33	public class CustomAuthenticationFailureHandler extends SimpleUrlAuthenticationFailureHandler {
34	
35	    private final AccountLockoutService lockoutService;
36	    private final LocalCaptchaService captchaService;
37	
38	    @Value("${app.captcha.show-after-failures:3}")
39	    private int captchaThreshold;
40	
41	    @Override
42	    public void onAuthenticationFailure(HttpServletRequest request,
43	                                        HttpServletResponse response,
44	                                        AuthenticationException exception)
45	            throws IOException, ServletException {
46	
47	        String username = request.getParameter("username");
48	        String ip = clientIp(request);
49	        HttpSession session = request.getSession(true);
50	
51	        // Step 1: track the failed attempt against the database — this is what drives lockout.
52	        lockoutService.trackFailedAttempt(username, ip);
53	
54	        // Step 2: if the previous render required a CAPTCHA, validate it. A wrong CAPTCHA
55	        //         counts as a failed attempt (already tracked) but we don't reveal which part failed.
56	        boolean captchaWasRequired = Boolean.TRUE.equals(session.getAttribute("captchaRequired"));
57	        if (captchaWasRequired) {
58	            String captchaInput = request.getParameter("captcha");
59	            boolean captchaOk = captchaService.validateAnswer(session, captchaInput);
60	            log.debug("CAPTCHA validation for failed login: {}", captchaOk ? "ok" : "fail");
61	        }
62	
63	        // Step 3: bump the captchaRequired flag if we're now at the show-CAPTCHA threshold.
64	        long failures = lockoutService.currentFailureCount(username);
65	        if (failures >= captchaThreshold) {
66	            session.setAttribute("captchaRequired", Boolean.TRUE);
67	        }
68	
69	        // Step 4: choose the appropriate redirect.
70	        String redirect;
71	        if (lockoutService.isIpBlocked(ip)) {
72	            log.warn("IP {} is now blocked (too many failures)", ip);
73	            redirect = "/login?ipblocked";
74	        } else if (lockoutService.isAccountLocked(username)) {
75	            log.warn("Account '{}' is now locked", username);
76	            redirect = "/login?locked";
77	        } else {
78	            redirect = "/login?error";
79	        }
80	        getRedirectStrategy().sendRedirect(request, response, redirect);
81	    }
82	
83	    /** X-Forwarded-For aware client IP extraction. */
84	    private String clientIp(HttpServletRequest request) {
85	        String header = request.getHeader("X-Forwarded-For");
86	        if (header != null && !header.isBlank()) {
87	            return header.split(",")[0].trim();
88	        }
89	        return request.getRemoteAddr();
90	    }
91	}
