1	package com.meridian.retail.security;
2	
3	import com.meridian.retail.entity.LoginAttempt;
4	import com.meridian.retail.repository.LoginAttemptRepository;
5	import lombok.RequiredArgsConstructor;
6	import lombok.extern.slf4j.Slf4j;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.stereotype.Service;
9	
10	import java.time.LocalDateTime;
11	
12	/**
13	 * Account / IP lockout per SPEC.md:
14	 *   - 5 failed attempts per account within 15 minutes  -> account locked for 15 minutes
15	 *   - 20 failed attempts per IP address within 60 min  -> IP blocked for the remainder of the hour
16	 *
17	 * The "lock duration" is enforced implicitly by the time-window query: once the oldest
18	 * failure falls outside the window, the count drops below the threshold and the account
19	 * unlocks. This means we never have to write a separate "unlock_at" column or run a
20	 * scheduled unlock job — the data IS the lock state.
21	 *
22	 * QA-facing readability: every public method here is a single, explicit query against
23	 * login_attempts. No magic, no caching layer. The static-audit reviewer can verify lockout
24	 * by reading these 4 methods and one repository interface.
25	 */
26	@Service
27	@RequiredArgsConstructor
28	@Slf4j
29	public class AccountLockoutService {
30	
31	    private final LoginAttemptRepository loginAttemptRepository;
32	
33	    @Value("${app.lockout.account-max-attempts:5}")
34	    private int accountMaxAttempts;
35	
36	    @Value("${app.lockout.account-window-minutes:15}")
37	    private int accountWindowMinutes;
38	
39	    @Value("${app.lockout.ip-max-attempts:20}")
40	    private int ipMaxAttempts;
41	
42	    @Value("${app.lockout.ip-window-minutes:60}")
43	    private int ipWindowMinutes;
44	
45	    /**
46	     * Returns true if {@code username} has accumulated >= 5 failed attempts in the last 15 minutes.
47	     * The lock automatically lifts once the oldest failure ages out of the window.
48	     */
49	    public boolean isAccountLocked(String username) {
50	        if (username == null || username.isBlank()) return false;
51	        LocalDateTime windowStart = LocalDateTime.now().minusMinutes(accountWindowMinutes);
52	        long failures = loginAttemptRepository
53	                .countByUsernameAndSuccessFalseAndAttemptedAtAfter(username, windowStart);
54	        return failures >= accountMaxAttempts;
55	    }
56	
57	    /**
58	     * Returns true if {@code ipAddress} has accumulated >= 20 failed attempts in the last 60 minutes.
59	     */
60	    public boolean isIpBlocked(String ipAddress) {
61	        if (ipAddress == null || ipAddress.isBlank()) return false;
62	        LocalDateTime windowStart = LocalDateTime.now().minusMinutes(ipWindowMinutes);
63	        long failures = loginAttemptRepository
64	                .countByIpAddressAndSuccessFalseAndAttemptedAtAfter(ipAddress, windowStart);
65	        return failures >= ipMaxAttempts;
66	    }
67	
68	    /**
69	     * Records a single failed login attempt. Always called from
70	     * {@link CustomAuthenticationFailureHandler} BEFORE the lockout check, so the call that
71	     * pushes the account over the threshold is itself counted.
72	     */
73	    public void trackFailedAttempt(String username, String ipAddress) {
74	        LoginAttempt attempt = LoginAttempt.builder()
75	                .username(username == null ? "" : username)
76	                .ipAddress(ipAddress == null ? "" : ipAddress)
77	                .success(false)
78	                .attemptedAt(LocalDateTime.now())
79	                .build();
80	        loginAttemptRepository.save(attempt);
81	        log.warn("Failed login tracked: user={} ip={}", username, ipAddress);
82	    }
83	
84	    /** Records a successful login (kept for analytics + visible "last login" tracking). */
85	    public void trackSuccessfulAttempt(String username, String ipAddress) {
86	        LoginAttempt attempt = LoginAttempt.builder()
87	                .username(username == null ? "" : username)
88	                .ipAddress(ipAddress == null ? "" : ipAddress)
89	                .success(true)
90	                .attemptedAt(LocalDateTime.now())
91	                .build();
92	        loginAttemptRepository.save(attempt);
93	    }
94	
95	    /**
96	     * Clears the failed-attempt history for a username on successful login. Without this
97	     * the failure count would re-trigger lockout the next time the user typed a wrong password.
98	     */
99	    public void resetAttempts(String username) {
100	        if (username == null || username.isBlank()) return;
101	        loginAttemptRepository.deleteByUsername(username);
102	    }
103	
104	    /** Returns the current failure count for the account window — used to decide if CAPTCHA must show. */
105	    public long currentFailureCount(String username) {
106	        if (username == null || username.isBlank()) return 0;
107	        LocalDateTime windowStart = LocalDateTime.now().minusMinutes(accountWindowMinutes);
108	        return loginAttemptRepository
109	                .countByUsernameAndSuccessFalseAndAttemptedAtAfter(username, windowStart);
110	    }
111	}
