1	package com.meridian.retail.security;
2	
3	import jakarta.servlet.http.HttpSession;
4	import org.springframework.stereotype.Service;
5	
6	import java.awt.*;
7	import java.awt.geom.AffineTransform;
8	import java.awt.image.BufferedImage;
9	import java.security.SecureRandom;
10	
11	/**
12	 * Locally-generated CAPTCHA — no external service, no internet required.
13	 *
14	 * generateImage() draws a 200x60 BufferedImage of 6 random alphanumeric characters
15	 * with mild rotation and a few noise lines. The plaintext answer is stashed in the
16	 * HTTP session under {@link #SESSION_KEY}; validateAnswer() reads it back, compares
17	 * case-insensitively, and clears the session attribute on success so the same answer
18	 * cannot be replayed.
19	 */
20	@Service
21	public class LocalCaptchaService {
22	
23	    public static final String SESSION_KEY = "CAPTCHA_ANSWER";
24	
25	    private static final String CHARSET = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"; // skip ambiguous chars
26	    private static final int CODE_LENGTH = 6;
27	    private static final int WIDTH  = 200;
28	    private static final int HEIGHT = 60;
29	    private static final SecureRandom RNG = new SecureRandom();
30	
31	    /** Generates a CAPTCHA image and stores its plaintext answer in the session. */
32	    public BufferedImage generateImage(HttpSession session) {
33	        String code = randomCode();
34	        session.setAttribute(SESSION_KEY, code);
35	
36	        BufferedImage img = new BufferedImage(WIDTH, HEIGHT, BufferedImage.TYPE_INT_RGB);
37	        Graphics2D g = img.createGraphics();
38	        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
39	
40	        // Background
41	        g.setColor(new Color(248, 250, 252));
42	        g.fillRect(0, 0, WIDTH, HEIGHT);
43	
44	        // Noise lines
45	        for (int i = 0; i < 5; i++) {
46	            g.setColor(new Color(RNG.nextInt(120) + 80, RNG.nextInt(120) + 80, RNG.nextInt(120) + 80));
47	            g.drawLine(RNG.nextInt(WIDTH), RNG.nextInt(HEIGHT),
48	                       RNG.nextInt(WIDTH), RNG.nextInt(HEIGHT));
49	        }
50	
51	        // Characters with per-char rotation
52	        Font baseFont = new Font(Font.SANS_SERIF, Font.BOLD, 32);
53	        int x = 18;
54	        for (char c : code.toCharArray()) {
55	            int fontSize = 30 + RNG.nextInt(7); // 30..36
56	            Font font = baseFont.deriveFont((float) fontSize);
57	            g.setFont(font);
58	
59	            double angleDegrees = (RNG.nextDouble() * 30) - 15; // -15..+15 degrees
60	            AffineTransform original = g.getTransform();
61	            AffineTransform rotated = new AffineTransform(original);
62	            rotated.rotate(Math.toRadians(angleDegrees), x + 10, HEIGHT / 2.0);
63	            g.setTransform(rotated);
64	
65	            g.setColor(new Color(30 + RNG.nextInt(60), 30 + RNG.nextInt(60), 80 + RNG.nextInt(80)));
66	            g.drawString(String.valueOf(c), x, HEIGHT - 18);
67	
68	            g.setTransform(original);
69	            x += 28;
70	        }
71	
72	        g.dispose();
73	        return img;
74	    }
75	
76	    /**
77	     * Compares the user's typed answer to the value stashed in the session, case-insensitively.
78	     * On success the answer is removed from the session so the same image cannot be reused.
79	     */
80	    public boolean validateAnswer(HttpSession session, String userInput) {
81	        if (session == null || userInput == null) return false;
82	        Object stored = session.getAttribute(SESSION_KEY);
83	        if (stored == null) return false;
84	        boolean match = stored.toString().equalsIgnoreCase(userInput.trim());
85	        if (match) {
86	            session.removeAttribute(SESSION_KEY);
87	        }
88	        return match;
89	    }
90	
91	    private String randomCode() {
92	        StringBuilder sb = new StringBuilder(CODE_LENGTH);
93	        for (int i = 0; i < CODE_LENGTH; i++) {
94	            sb.append(CHARSET.charAt(RNG.nextInt(CHARSET.length())));
95	        }
96	        return sb.toString();
97	    }
98	}
