2	
3	import com.meridian.retail.entity.CampaignAttachment;
4	import com.meridian.retail.entity.TempDownloadLink;
5	import com.meridian.retail.entity.UploadSession;
6	import com.meridian.retail.repository.CampaignAttachmentRepository;
7	import com.meridian.retail.repository.CampaignRepository;
