9	import com.meridian.retail.storage.LinkExpiredException;
10	import com.meridian.retail.storage.MaskedDownloadService;
11	import com.meridian.retail.storage.StorageException;
12	import com.meridian.retail.storage.TempDownloadLinkService;
13	import jakarta.servlet.http.HttpServletRequest;
14	import jakarta.servlet.http.HttpServletResponse;
15	import lombok.RequiredArgsConstructor;
16	import org.springframework.http.HttpStatus;
17	import org.springframework.http.MediaType;
18	import org.springframework.http.ResponseEntity;
19	import org.springframework.security.access.AccessDeniedException;
20	import org.springframework.security.access.prepost.PreAuthorize;
21	import org.springframework.security.core.Authentication;
22	import org.springframework.security.core.GrantedAuthority;
23	import org.springframework.stereotype.Controller;
24	import org.springframework.ui.Model;
25	import org.springframework.web.bind.annotation.*;
26	import org.springframework.web.multipart.MultipartFile;
27	
28	import java.io.IOException;
29	import java.util.List;
30	import java.util.Map;
31	
32	/**
33	 * File upload + download endpoints.
34	 *
35	 * Upload protocol:
36	 *   POST /files/upload/init                {campaignId, filename, totalChunks}
37	 *   POST /files/upload/chunk               body=chunk bytes; headers Upload-Id, Chunk-Index
38	 *   GET  /files/upload/status/{uploadId}   JSON {progress, receivedChunks, status}
39	 *   POST /files/upload/finalize/{uploadId}
40	 *
41	 * Download:
42	 *   GET /files/attachment/{id}/download  -> generates a temp link, redirects to /files/download/{token}
43	 *   GET /files/download/{token}          -> resolves token, streams file (or watermarked rendition)
44	 */
45	@Controller
46	@RequestMapping("/files")
47	@RequiredArgsConstructor
48	public class FileController {
49	
50	    private final ChunkedUploadService chunkedUploadService;
51	    private final TempDownloadLinkService tempLinkService;
52	    private final MaskedDownloadService maskedDownloadService;
53	    private final CampaignAttachmentRepository attachmentRepository;
54	    private final CampaignRepository campaignRepository;
55	
56	    /** Upload landing page (drag-and-drop UI). */
57	    @GetMapping("/upload")
58	    @PreAuthorize("hasAnyRole('OPERATIONS','ADMIN')")
59	    public String uploadPage(@RequestParam(required = false) Long campaignId, Model model) {
60	        model.addAttribute("breadcrumb", "Upload Files");
61	        model.addAttribute("campaigns", campaignRepository.findByDeletedAtIsNullOrderByCreatedAtDesc());
62	        model.addAttribute("selectedCampaignId", campaignId);
63	        if (campaignId != null) {
64	            model.addAttribute("attachments",
65	                    attachmentRepository.findByCampaignIdOrderByVersionDesc(campaignId));
66	        } else {
67	            model.addAttribute("attachments", List.of());
68	        }
69	        return "upload/upload";
70	    }
71	
72	    @PostMapping(value = "/upload/init", produces = MediaType.APPLICATION_JSON_VALUE)
73	    @PreAuthorize("hasAnyRole('OPERATIONS','ADMIN')")
74	    @ResponseBody
75	    public Map<String, Object> initUpload(@RequestParam Long campaignId,
76	                                          @RequestParam String filename,
77	                                          @RequestParam int totalChunks,
78	                                          Authentication auth) {
79	        UploadSession session = chunkedUploadService.initUpload(campaignId, filename, totalChunks, auth.getName());
80	        return Map.of(
81	                "uploadId", session.getUploadId(),
82	                "totalChunks", session.getTotalChunks()
83	        );
84	    }
85	
86	    @PostMapping(value = "/upload/chunk", produces = MediaType.APPLICATION_JSON_VALUE)
87	    @PreAuthorize("hasAnyRole('OPERATIONS','ADMIN')")
88	    @ResponseBody
89	    public Map<String, Object> uploadChunk(@RequestHeader("Upload-Id") String uploadId,
90	                                           @RequestHeader("Chunk-Index") int chunkIndex,
91	                                           @RequestParam("chunk") MultipartFile chunk) throws IOException {
92	        UploadSession session = chunkedUploadService.receiveChunk(uploadId, chunkIndex, chunk.getBytes());
93	        var status = chunkedUploadService.getStatus(uploadId).orElseThrow();
94	        return status;
95	    }
96	
97	    @GetMapping(value = "/upload/status/{uploadId}", produces = MediaType.APPLICATION_JSON_VALUE)
98	    @PreAuthorize("hasAnyRole('OPERATIONS','ADMIN')")
99	    @ResponseBody
100	    public ResponseEntity<Map<String, Object>> uploadStatus(@PathVariable String uploadId) {
101	        return chunkedUploadService.getStatus(uploadId)
102	                .map(ResponseEntity::ok)
103	                .orElseGet(() -> ResponseEntity.notFound().build());
104	    }
105	
106	    @PostMapping(value = "/upload/finalize/{uploadId}", produces = MediaType.APPLICATION_JSON_VALUE)
107	    @PreAuthorize("hasAnyRole('OPERATIONS','ADMIN')")
108	    @ResponseBody
109	    public Map<String, Object> finalizeUpload(@PathVariable String uploadId,
110	                                              Authentication auth,
111	                                              HttpServletRequest httpRequest) {
112	        CampaignAttachment saved = chunkedUploadService.finalizeUpload(uploadId, auth.getName(), clientIp(httpRequest));
113	        return Map.of(
114	                "id", saved.getId(),
115	                "filename", saved.getOriginalFilename(),
116	                "version", saved.getVersion(),
117	                "sha256", saved.getSha256Checksum(),
118	                "size", saved.getFileSizeBytes()
119	        );
120	    }
121	
122	    /** Generates a temp link bound to current user, redirects to it. */
123	    @GetMapping("/attachment/{id}/download")
124	    public String requestDownload(@PathVariable Long id,
125	                                  Authentication auth,
126	                                  HttpServletRequest httpRequest) {
127	        TempDownloadLink link = tempLinkService.generate(id, auth.getName(), clientIp(httpRequest));
128	        return "redirect:/files/download/" + link.getToken();
129	    }
130	
131	    @GetMapping("/download/{token}")
132	    public void download(@PathVariable String token,
133	                         Authentication auth,
134	                         HttpServletRequest httpRequest,
135	                         HttpServletResponse response) throws IOException {
136	        com.meridian.retail.storage.TempDownloadLinkService.Resolved resolved;
137	        try {
138	            // Resolve binds the token to the requesting user and marks it used.
139	            resolved = tempLinkService.resolve(token, auth.getName());
140	        } catch (LinkExpiredException e) {
141	            response.sendError(HttpStatus.GONE.value(), e.getMessage());
142	            return;
143	        } catch (AccessDeniedException e) {
144	            response.sendError(HttpStatus.FORBIDDEN.value(), e.getMessage());
145	            return;
146	        }
147	
148	        CampaignAttachment attachment = resolved.attachment();
149	        String role = auth.getAuthorities().stream()
150	                .map(GrantedAuthority::getAuthority)
151	                .findFirst().orElse("ROLE_USER")
152	                .replace("ROLE_", "");
153	
154	        try {
155	            String mime = maskedDownloadService.serve(attachment.getId(), auth.getName(), role,
156	                    clientIp(httpRequest), response.getOutputStream());
157	            response.setContentType(mime);
158	            response.setHeader("Content-Disposition",
159	                    "attachment; filename=\"" + attachment.getOriginalFilename() + "\"");
160	        } catch (AccessDeniedException e) {
161	            response.sendError(HttpStatus.FORBIDDEN.value(), e.getMessage());
162	        }
163	    }
164	
165	    /** Version history page for an attachment. */
166	    @GetMapping("/attachment/{id}/history")
167	    public String history(@PathVariable Long id, Model model) {
168	        CampaignAttachment current = attachmentRepository.findById(id)
169	                .orElseThrow(() -> new StorageException("Attachment not found: " + id));
170	        model.addAttribute("breadcrumb", "Attachment History");
171	        model.addAttribute("current", current);
172	        model.addAttribute("versions",
173	                attachmentRepository.findByOriginalFilenameAndCampaignIdOrderByVersionDesc(
174	                        current.getOriginalFilename(), current.getCampaignId()));
175	        return "upload/upload"; // reuse upload page which renders the history table
176	    }
177	
178	    private String clientIp(HttpServletRequest request) {
179	        String header = request.getHeader("X-Forwarded-For");
180	        if (header != null && !header.isBlank()) return header.split(",")[0].trim();
181	        return request.getRemoteAddr();
182	    }
183	}
