3	import jakarta.servlet.http.HttpSession;
4	import org.springframework.stereotype.Controller;
5	import org.springframework.ui.Model;
6	import org.springframework.web.bind.annotation.GetMapping;
7	import org.springframework.web.bind.annotation.RequestParam;
8	
9	/**
10	 * Renders the login page. Spring Security handles the actual POST /login submission.
11	 */
12	@Controller
13	public class LoginController {
14	
15	    @GetMapping("/login")
16	    public String login(@RequestParam(required = false) String error,
17	                        @RequestParam(required = false) String locked,
18	                        @RequestParam(required = false) String ipblocked,
19	                        @RequestParam(required = false) String logout,
20	                        HttpSession session,
21	                        Model model) {
22	
23	        if (error != null) {
24	            model.addAttribute("errorMessage", "Invalid username or password.");
25	        } else if (locked != null) {
26	            model.addAttribute("errorMessage",
27	                    "Account temporarily locked after too many failed attempts. Try again in 15 minutes.");
28	        } else if (ipblocked != null) {
29	            model.addAttribute("errorMessage",
30	                    "Too many failed attempts from your network. Access blocked for 1 hour.");
31	        } else if (logout != null) {
32	            model.addAttribute("successMessage", "You have been signed out.");
33	        }
34	
35	        Boolean captchaRequired = (Boolean) session.getAttribute("captchaRequired");
36	        model.addAttribute("captchaRequired", Boolean.TRUE.equals(captchaRequired));
37	
38	        return "auth/login";
39	    }
40	
41	    /** Root route — Spring Security forwards to /login if anonymous; if authenticated, send to / via dashboard router. */
42	    @GetMapping("/")
