1	package com.meridian.retail.storage;
2	
3	import com.meridian.retail.entity.CampaignAttachment;
4	import com.meridian.retail.entity.TempDownloadLink;
5	import com.meridian.retail.repository.CampaignAttachmentRepository;
6	import com.meridian.retail.repository.TempDownloadLinkRepository;
7	import lombok.RequiredArgsConstructor;
8	import org.springframework.beans.factory.annotation.Value;
9	import org.springframework.security.access.AccessDeniedException;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.nio.file.Path;
14	import java.nio.file.Paths;
15	import java.time.LocalDateTime;
16	import java.util.UUID;
17	
18	/**
19	 * Per-user, time-limited download tokens.
20	 *
21	 * SPEC.md: temporary download links expire after 10 minutes and are bound to the
22	 * requesting user. We enforce both rules in resolve() and additionally mark the link
23	 * as used so the same token cannot be replayed even within the 10-minute window.
24	 */
25	@Service
26	@RequiredArgsConstructor
27	public class TempDownloadLinkService {
28	
29	    private final TempDownloadLinkRepository linkRepository;
30	    private final CampaignAttachmentRepository attachmentRepository;
31	
32	    @Value("${app.temp-link.expiry-minutes:10}")
33	    private int expiryMinutes;
34	
35	    @Transactional
36	    public TempDownloadLink generate(Long fileId, String username, String ipAddress) {
37	        CampaignAttachment file = attachmentRepository.findById(fileId)
38	                .orElseThrow(() -> new StorageException("Attachment not found: " + fileId));
39	
40	        TempDownloadLink link = TempDownloadLink.builder()
41	                .token(UUID.randomUUID().toString())
42	                .fileId(file.getId())
43	                .username(username)
44	                .ipAddress(ipAddress)
45	                .expiresAt(LocalDateTime.now().plusMinutes(expiryMinutes))
46	                .build();
47	        return linkRepository.save(link);
48	    }
49	
50	    /** Resolved download = (attachment, filesystem path) returned together. */
51	    public record Resolved(CampaignAttachment attachment, Path path) {}
52	
53	    /**
54	     * Resolves a token to its file. Validates expiry, single-use, and user binding.
55	     * Throws LinkExpiredException, AccessDeniedException, or StorageException as appropriate.
56	     */
57	    @Transactional
58	    public Resolved resolve(String token, String requestingUsername) {
59	        TempDownloadLink link = linkRepository.findByToken(token)
60	                .orElseThrow(() -> new StorageException("Unknown download token"));
61	
62	        if (link.getExpiresAt().isBefore(LocalDateTime.now())) {
63	            throw new LinkExpiredException("Download link has expired");
64	        }
65	        if (link.getUsedAt() != null) {
66	            throw new LinkExpiredException("Download link has already been used");
67	        }
68	        if (!link.getUsername().equalsIgnoreCase(requestingUsername)) {
69	            throw new AccessDeniedException("Download link is bound to a different user");
70	        }
71	
72	        link.setUsedAt(LocalDateTime.now());
73	        linkRepository.save(link);
74	
75	        CampaignAttachment file = attachmentRepository.findById(link.getFileId())
76	                .orElseThrow(() -> new StorageException("Attachment not found"));
77	        return new Resolved(file, Paths.get(file.getStoredPath()));
78	    }
79	}
