1	package com.meridian.retail.storage;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.entity.CampaignAttachment;
6	import com.meridian.retail.repository.CampaignAttachmentRepository;
7	import lombok.RequiredArgsConstructor;
8	import lombok.extern.slf4j.Slf4j;
9	import org.springframework.stereotype.Service;
10	
11	import java.io.OutputStream;
12	import java.nio.file.Files;
13	import java.nio.file.Path;
14	import java.nio.file.Paths;
15	import java.util.Map;
16	import java.util.Set;
17	
18	/**
19	 * Masked download policy:
20	 *
21	 *   - Public attachment        -> stream original to anyone authenticated
22	 *   - Internal-only attachment:
23	 *       - role IN masked_roles -> stream the original
24	 *       - role NOT in list:
25	 *           - PDF or image     -> stream watermarked rendition
26	 *           - other binary     -> 403
27	 *
28	 * Every access — original or watermarked — writes an AuditLog row.
29	 */
30	@Service
31	@RequiredArgsConstructor
32	@Slf4j
33	public class MaskedDownloadService {
34	
35	    private final CampaignAttachmentRepository attachmentRepository;
36	    private final WatermarkService watermarkService;
37	    private final AuditLogService auditLogService;
38	
39	    private static final Set<String> WATERMARKABLE = Set.of(
40	            "application/pdf", "image/png", "image/jpeg", "image/gif"
41	    );
42	
43	    /** Returns true if {@code role} appears in the JSON list stored on the attachment. */
44	    public boolean canAccessOriginal(CampaignAttachment attachment, String role) {
45	        if (!attachment.isInternalOnly()) return true;
46	        String masked = attachment.getMaskedRoles();
47	        if (masked == null || masked.isBlank()) return false;
48	        // The masked_roles JSON is a small list of role strings — substring match is fine.
49	        return masked.contains("\"" + role + "\"");
50	    }
51	
52	    /**
53	     * Streams the file (original or watermarked) to the response output stream.
54	     * Returns the MIME type that should be set on the response.
55	     */
56	    public String serve(Long attachmentId, String username, String role, String ipAddress, OutputStream out) {
57	        CampaignAttachment file = attachmentRepository.findById(attachmentId)
58	                .orElseThrow(() -> new StorageException("Attachment not found: " + attachmentId));
59	        Path path = Paths.get(file.getStoredPath());
60	
61	        boolean originalAccess = canAccessOriginal(file, role);
62	
63	        if (originalAccess) {
64	            try {
65	                Files.copy(path, out);
66	            } catch (Exception e) {
67	                throw new StorageException("Failed to stream attachment " + attachmentId, e);
68	            }
69	            // AUDIT: original download
70	            auditLogService.log(AuditAction.FILE_DOWNLOADED, "CampaignAttachment", file.getId(),
71	                    null, Map.of("filename", file.getOriginalFilename(), "watermarked", false),
72	                    username, ipAddress);
73	            return file.getFileType();
74	        }
75	
76	        // Not authorized for the original — watermarked rendition or 403.
77	        if (!WATERMARKABLE.contains(file.getFileType())) {
78	            // AUDIT: blocked masked access (binary file)
79	            auditLogService.log(AuditAction.FILE_MASKED_ACCESS, "CampaignAttachment", file.getId(),
80	                    null, Map.of("blocked", true, "reason", "non-watermarkable binary"),
81	                    username, ipAddress);
82	            throw new org.springframework.security.access.AccessDeniedException(
83	                    "This attachment cannot be masked for your role");
84	        }
85	
86	        if ("application/pdf".equals(file.getFileType())) {
87	            watermarkService.addPdfWatermark(path, username, out);
88	            auditLogService.log(AuditAction.FILE_MASKED_ACCESS, "CampaignAttachment", file.getId(),
89	                    null, Map.of("watermarked", true, "type", "pdf"),
90	                    username, ipAddress);
91	            return "application/pdf";
92	        } else {
93	            watermarkService.addImageWatermark(path, file.getFileType(), username, out);
94	            auditLogService.log(AuditAction.FILE_MASKED_ACCESS, "CampaignAttachment", file.getId(),
95	                    null, Map.of("watermarked", true, "type", "image"),
96	                    username, ipAddress);
97	            return "image/png"; // image watermark always re-encodes to PNG
98	        }
99	    }
100	}
