1	package com.meridian.retail.storage;
2	
3	import com.fasterxml.jackson.core.type.TypeReference;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.meridian.retail.audit.AuditAction;
6	import com.meridian.retail.audit.AuditLogService;
7	import com.meridian.retail.entity.AttachmentStatus;
8	import com.meridian.retail.entity.CampaignAttachment;
9	import com.meridian.retail.entity.UploadSession;
10	import com.meridian.retail.repository.CampaignAttachmentRepository;
11	import com.meridian.retail.repository.UploadSessionRepository;
12	import lombok.RequiredArgsConstructor;
13	import lombok.extern.slf4j.Slf4j;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.io.ByteArrayInputStream;
18	import java.nio.file.Files;
19	import java.nio.file.Path;
20	import java.util.ArrayList;
21	import java.util.List;
22	import java.util.Map;
23	import java.util.Optional;
24	import java.util.UUID;
25	
26	/**
27	 * Resumable, chunked upload protocol:
28	 *
29	 *   POST /files/upload/init       -> ChunkedUploadService.initUpload   (returns uploadId)
30	 *   POST /files/upload/chunk      -> ChunkedUploadService.receiveChunk (per chunk)
31	 *   GET  /files/upload/status/{}  -> ChunkedUploadService.getStatus    (HTMX polling)
32	 *   POST /files/upload/finalize/{}-> ChunkedUploadService.finalizeUpload
33	 *
34	 * After receiveChunk the upload session's received_chunks JSON list grows. Once all
35	 * chunks have been written, finalizeUpload assembles them, validates the MIME via Tika,
36	 * computes SHA-256, persists a CampaignAttachment row, and writes an audit log entry.
37	 */
38	@Service
39	@RequiredArgsConstructor
40	@Slf4j
41	public class ChunkedUploadService {
42	
43	    private final UploadSessionRepository sessionRepository;
44	    private final CampaignAttachmentRepository attachmentRepository;
45	    private final StorageService storageService;
46	    private final FileValidationService fileValidationService;
47	    private final AuditLogService auditLogService;
48	    private final ObjectMapper objectMapper;
49	
50	    @Transactional
51	    public UploadSession initUpload(Long campaignId, String filename, int totalChunks, String username) {
52	        if (totalChunks <= 0) {
53	            throw new StorageException("totalChunks must be positive");
54	        }
55	        String uploadId = UUID.randomUUID().toString();
56	        Path tempDir = storageService.getTempDir(uploadId);
57	
58	        UploadSession session = UploadSession.builder()
59	                .uploadId(uploadId)
60	                .campaignId(campaignId)
61	                .originalFilename(filename)
62	                .totalChunks(totalChunks)
63	                .receivedChunks("[]")
64	                .tempDir(tempDir.toString())
65	                .status(AttachmentStatus.IN_PROGRESS)
66	                .startedBy(username)
67	                .build();
68	        return sessionRepository.save(session);
69	    }
70	
71	    @Transactional
72	    public UploadSession receiveChunk(String uploadId, int chunkIndex, byte[] bytes) {
73	        UploadSession session = sessionRepository.findByUploadId(uploadId)
74	                .orElseThrow(() -> new StorageException("Unknown uploadId: " + uploadId));
75	        if (session.getStatus() != AttachmentStatus.IN_PROGRESS) {
76	            throw new StorageException("Upload not in progress: " + session.getStatus());
77	        }
78	        if (chunkIndex < 0 || chunkIndex >= session.getTotalChunks()) {
79	            throw new StorageException("Chunk index out of range");
80	        }
81	        storageService.storeChunk(uploadId, chunkIndex, bytes);
82	
83	        List<Integer> received = parseChunkList(session.getReceivedChunks());
84	        if (!received.contains(chunkIndex)) received.add(chunkIndex);
85	        session.setReceivedChunks(toJson(received));
86	        return sessionRepository.save(session);
87	    }
88	
89	    public Optional<Map<String, Object>> getStatus(String uploadId) {
90	        return sessionRepository.findByUploadId(uploadId).map(s -> {
91	            List<Integer> received = parseChunkList(s.getReceivedChunks());
92	            int progress = s.getTotalChunks() == 0 ? 0
93	                    : (int) Math.round(100.0 * received.size() / s.getTotalChunks());
94	            return Map.of(
95	                    "uploadId", s.getUploadId(),
96	                    "totalChunks", s.getTotalChunks(),
97	                    "receivedChunks", received,
98	                    "progress", progress,
99	                    "status", s.getStatus().name()
100	            );
101	        });
102	    }
103	
104	    @Transactional
105	    public CampaignAttachment finalizeUpload(String uploadId, String username, String ipAddress) {
106	        UploadSession session = sessionRepository.findByUploadId(uploadId)
107	                .orElseThrow(() -> new StorageException("Unknown uploadId: " + uploadId));
108	        if (session.getStatus() != AttachmentStatus.IN_PROGRESS) {
109	            throw new StorageException("Upload already finalized");
110	        }
111	
112	        List<Integer> received = parseChunkList(session.getReceivedChunks());
113	        if (received.size() != session.getTotalChunks()) {
114	            throw new StorageException("Cannot finalize — missing chunks (" + received.size()
115	                    + " of " + session.getTotalChunks() + ")");
116	        }
117	
118	        // Determine version number for this filename in this campaign
119	        List<CampaignAttachment> existing = attachmentRepository
120	                .findByOriginalFilenameAndCampaignIdOrderByVersionDesc(
121	                        session.getOriginalFilename(), session.getCampaignId());
122	        int nextVersion = existing.isEmpty() ? 1 : existing.get(0).getVersion() + 1;
123	
124	        String storedFilename = "v" + nextVersion + "_" + sanitizeFilename(session.getOriginalFilename());
125	        Path destPath = storageService.getCampaignDir(session.getCampaignId()).resolve(storedFilename);
126	
127	        storageService.assembleChunks(uploadId, session.getTotalChunks(), destPath);
128	
129	        long fileSize;
130	        try {
131	            fileSize = Files.size(destPath);
132	        } catch (Exception e) {
133	            throw new StorageException("Cannot stat assembled file", e);
134	        }
135	        fileValidationService.validateSize(fileSize);
136	
137	        // MIME validation reads the first few bytes from the assembled file.
138	        String mime;
139	        try (var in = Files.newInputStream(destPath)) {
140	            mime = fileValidationService.detectAndValidateMime(in);
141	        } catch (Exception e) {
142	            throw new StorageException("Failed to validate file MIME", e);
143	        }
144	
145	        String sha256 = storageService.computeSha256(destPath);
146	
147	        CampaignAttachment attachment = CampaignAttachment.builder()
148	                .campaignId(session.getCampaignId())
149	                .originalFilename(session.getOriginalFilename())
150	                .storedFilename(storedFilename)
151	                .storedPath(destPath.toString())
152	                .fileType(mime)
153	                .fileSizeBytes(fileSize)
154	                .sha256Checksum(sha256)
155	                .internalOnly(false)
156	                .maskedRoles(null)
157	                .version(nextVersion)
158	                .uploadedBy(username)
159	                .build();
160	        CampaignAttachment saved = attachmentRepository.save(attachment);
161	
162	        session.setStatus(AttachmentStatus.COMPLETE);
163	        sessionRepository.save(session);
164	        storageService.cleanupTemp(uploadId);
165	
166	        // AUDIT: file uploads must always leave a record (operator + checksum visible).
167	        auditLogService.log(AuditAction.FILE_UPLOADED, "CampaignAttachment", saved.getId(),
168	                null, Map.of(
169	                        "filename", saved.getOriginalFilename(),
170	                        "version", saved.getVersion(),
171	                        "sha256", saved.getSha256Checksum(),
172	                        "size", saved.getFileSizeBytes()
173	                ),
174	                username, ipAddress);
175	
176	        return saved;
177	    }
178	
179	    /** Convenience for tests / direct (non-chunked) writes. */
180	    public CampaignAttachment storeSingleFile(Long campaignId, String filename,
181	                                              byte[] data, String username, String ipAddress) {
182	        UploadSession s = initUpload(campaignId, filename, 1, username);
183	        receiveChunk(s.getUploadId(), 0, data);
184	        return finalizeUpload(s.getUploadId(), username, ipAddress);
185	    }
186	
187	    private List<Integer> parseChunkList(String json) {
188	        if (json == null || json.isBlank()) return new ArrayList<>();
189	        try {
190	            return objectMapper.readValue(json, new TypeReference<List<Integer>>() {});
191	        } catch (Exception e) {
192	            return new ArrayList<>();
193	        }
194	    }
195	
196	    private String toJson(List<Integer> list) {
197	        try {
198	            return objectMapper.writeValueAsString(list);
199	        } catch (Exception e) {
200	            return "[]";
201	        }
202	    }
203	
204	    private String sanitizeFilename(String filename) {
205	        if (filename == null) return "file";
206	        return filename.replaceAll("[^a-zA-Z0-9._-]", "_");
207	    }
208	}
