1	// Chunked upload client. Reads the selected File, splits it into 1 MB chunks,
2	// POSTs each chunk to /files/upload/chunk, polls /status until complete, then finalises.
3	
4	(function () {
5	    const CHUNK_SIZE = 1024 * 1024;
6	
7	    const zone     = document.getElementById('upload-zone');
8	    const input    = document.getElementById('file-input');
9	    const progress = document.getElementById('upload-progress');
10	    const bar      = document.getElementById('upload-bar');
11	    const counter  = document.getElementById('chunk-counter');
12	    const nameEl   = document.getElementById('uploading-name');
13	    const finalDiv = document.getElementById('finalized');
14	    const shaEl    = document.getElementById('sha256');
15	    const statusBadge = document.getElementById('upload-status-badge');
16	
17	    if (!zone) return;
18	
19	    const csrfToken  = document.querySelector('meta[name="_csrf"]').getAttribute('content');
20	    const csrfHeader = document.querySelector('meta[name="_csrf_header"]').getAttribute('content');
21	
22	    zone.addEventListener('click', () => input.click());
23	    zone.addEventListener('dragover', e => { e.preventDefault(); zone.classList.add('dragover'); });
24	    zone.addEventListener('dragleave', () => zone.classList.remove('dragover'));
25	    zone.addEventListener('drop', e => {
26	        e.preventDefault();
27	        zone.classList.remove('dragover');
28	        if (e.dataTransfer.files.length) handleFile(e.dataTransfer.files[0]);
29	    });
30	    input.addEventListener('change', e => {
31	        if (e.target.files.length) handleFile(e.target.files[0]);
32	    });
33	
34	    async function handleFile(file) {
35	        nameEl.textContent = file.name;
36	        progress.classList.remove('d-none');
37	        finalDiv.classList.add('d-none');
38	        statusBadge.textContent = 'UPLOADING';
39	        statusBadge.className = 'status-badge status-pending';
40	        bar.style.width = '0%';
41	        bar.textContent = '0%';
42	
43	        const totalChunks = Math.max(1, Math.ceil(file.size / CHUNK_SIZE));
44	        counter.textContent = '0 of ' + totalChunks + ' chunks received';
45	
46	        // Init
47	        const initParams = new URLSearchParams();
48	        initParams.append('campaignId', window.RC_CAMPAIGN_ID);
49	        initParams.append('filename', file.name);
50	        initParams.append('totalChunks', totalChunks);
51	
52	        const initRes = await fetch('/files/upload/init', {
53	            method: 'POST',
54	            headers: { [csrfHeader]: csrfToken, 'Content-Type': 'application/x-www-form-urlencoded' },
55	            body: initParams
56	        });
57	        if (!initRes.ok) { failed('Init failed'); return; }
58	        const init = await initRes.json();
59	        const uploadId = init.uploadId;
60	
61	        // Send chunks sequentially
62	        for (let i = 0; i < totalChunks; i++) {
63	            const start = i * CHUNK_SIZE;
64	            const end = Math.min(start + CHUNK_SIZE, file.size);
65	            const blob = file.slice(start, end);
66	            const fd = new FormData();
67	            fd.append('chunk', blob, 'chunk-' + i);
68	
69	            const r = await fetch('/files/upload/chunk', {
70	                method: 'POST',
71	                headers: { [csrfHeader]: csrfToken, 'Upload-Id': uploadId, 'Chunk-Index': String(i) },
72	                body: fd
73	            });
74	            if (!r.ok) { failed('Chunk ' + i + ' upload failed'); return; }
75	            const status = await r.json();
76	            updateProgress(status.progress, status.receivedChunks.length, totalChunks);
77	        }
78	
79	        // Finalize
80	        const fin = await fetch('/files/upload/finalize/' + uploadId, {
81	            method: 'POST',
82	            headers: { [csrfHeader]: csrfToken }
83	        });
84	        if (!fin.ok) { failed('Finalize failed'); return; }
85	        const result = await fin.json();
86	        statusBadge.textContent = 'COMPLETE';
87	        statusBadge.className = 'status-badge status-active';
88	        finalDiv.classList.remove('d-none');
89	        shaEl.textContent = result.sha256;
90	
91	        // Reload after a short delay so the version history table refreshes.
92	        setTimeout(() => window.location.reload(), 1500);
93	    }
94	
95	    function updateProgress(progressPct, received, total) {
96	        bar.style.width = progressPct + '%';
97	        bar.textContent = progressPct + '%';
98	        counter.textContent = received + ' of ' + total + ' chunks received';
99	    }
100	
101	    function failed(msg) {
102	        statusBadge.textContent = 'FAILED';
103	        statusBadge.className = 'status-badge status-rejected';
104	        counter.textContent = msg;
105	    }
106	})();
