1	package com.meridian.retail.service;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.dto.CouponDTO;
6	import com.meridian.retail.dto.CreateCouponRequest;
7	import com.meridian.retail.entity.Coupon;
8	import com.meridian.retail.repository.CouponRepository;
9	import com.meridian.retail.security.XssInputSanitizer;
10	import lombok.RequiredArgsConstructor;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.math.BigDecimal;
15	import java.util.HashSet;
16	import java.util.List;
17	import java.util.Set;
18	
19	@Service
20	@RequiredArgsConstructor
21	public class CouponService {
22	
23	    private final CouponRepository couponRepository;
24	    private final CampaignService campaignService;
25	    private final AuditLogService auditLogService;
26	
27	    public List<Coupon> listByCampaign(Long campaignId) {
28	        return couponRepository.findByCampaignId(campaignId);
29	    }
30	
31	    @Transactional
32	    public Coupon createCoupon(CreateCouponRequest req, String username, String ipAddress) {
33	        // Sanitize then validate
34	        String code = XssInputSanitizer.sanitize(req.getCode());
35	        if (code == null || code.isBlank()) {
36	            throw new CampaignValidationException("Coupon code is required");
37	        }
38	        if (couponRepository.existsByCodeIgnoreCase(code)) {
39	            throw new CampaignValidationException("Coupon code already in use: " + code);
40	        }
41	        // Defer to CampaignService for the discount value rule so it stays consistent.
42	        campaignService.validateDiscountValue(req.getDiscountType(), req.getDiscountValue());
43	
44	        Coupon c = Coupon.builder()
45	                .campaignId(req.getCampaignId())
46	                .code(code)
47	                .discountType(req.getDiscountType())
48	                .discountValue(req.getDiscountValue())
49	                .minPurchaseAmount(req.getMinPurchaseAmount() != null ? req.getMinPurchaseAmount() : BigDecimal.ZERO)
50	                .maxUses(req.getMaxUses())
51	                .stackable(req.isStackable())
52	                .mutualExclusionGroup(XssInputSanitizer.sanitize(req.getMutualExclusionGroup()))
53	                .validFrom(req.getValidFrom())
54	                .validUntil(req.getValidUntil())
55	                .build();
56	
57	        Coupon saved = couponRepository.save(c);
58	        auditLogService.log(AuditAction.COUPON_CREATED, "Coupon", saved.getId(),
59	                null, CouponDTO.from(saved), username, ipAddress);
60	        return saved;
61	    }
62	
63	    public boolean isCodeAvailable(String code) {
64	        if (code == null || code.isBlank()) return false;
65	        return !couponRepository.existsByCodeIgnoreCase(code);
66	    }
67	
68	    /**
69	     * Returns true if {@code candidate} can be combined with the supplied set of already-applied
70	     * coupon ids. Rules:
71	     *   - If the candidate is non-stackable AND the cart already has any coupon, reject.
72	     *   - If any existing coupon shares the candidate's mutual_exclusion_group, reject.
73	     */
74	    public boolean checkStackingCompatibility(Coupon candidate, List<Long> existingCouponIds) {
75	        if (candidate == null) return false;
76	        List<Coupon> existing = couponRepository.findAllById(existingCouponIds);
77	
78	        if (!candidate.isStackable() && !existing.isEmpty()) {
79	            return false;
80	        }
81	        for (Coupon e : existing) {
82	            if (!e.isStackable()) return false;
83	        }
84	
85	        Set<String> groups = new HashSet<>();
86	        if (candidate.getMutualExclusionGroup() != null) groups.add(candidate.getMutualExclusionGroup());
87	        for (Coupon e : existing) {
88	            if (e.getMutualExclusionGroup() != null && !groups.add(e.getMutualExclusionGroup())) {
89	                // Already present -> two coupons share an exclusion group -> reject.
90	                return false;
91	            }
92	        }
93	        // Also reject if candidate's group is already used by an existing coupon.
94	        if (candidate.getMutualExclusionGroup() != null) {
95	            for (Coupon e : existing) {
96	                if (candidate.getMutualExclusionGroup().equalsIgnoreCase(e.getMutualExclusionGroup())) {
97	                    return false;
98	                }
99	            }
100	        }
101	        return true;
102	    }
103	}
