1	package com.meridian.retail.service;
2	
3	import com.meridian.retail.audit.AuditAction;
4	import com.meridian.retail.audit.AuditLogService;
5	import com.meridian.retail.entity.User;
6	import com.meridian.retail.entity.UserRole;
7	import com.meridian.retail.repository.UserRepository;
8	import com.meridian.retail.security.PasswordValidationService;
9	import com.meridian.retail.security.XssInputSanitizer;
10	import lombok.RequiredArgsConstructor;
11	import org.springframework.security.crypto.password.PasswordEncoder;
12	import org.springframework.stereotype.Service;
13	import org.springframework.transaction.annotation.Transactional;
14	
15	import java.util.List;
16	import java.util.Map;
17	
18	/**
19	 * User management service. ALL mutations:
20	 *   - run XssInputSanitizer on string input
21	 *   - validate password complexity (12+ chars, upper/lower/digit/special)
22	 *   - persist BCrypt hashes (strength 12, matching seed data)
23	 *   - emit AuditLogService.log(...) with before/after snapshots
24	 *
25	 * Only ADMIN should ever invoke these methods — enforced by AdminController class-level
26	 * @PreAuthorize. The service itself does not re-check the role because the call site is
27	 * narrow and centralised; if that changes, add @PreAuthorize here too.
28	 */
29	@Service
30	@RequiredArgsConstructor
31	public class UserService {
32	
33	    private final UserRepository userRepository;
34	    private final PasswordEncoder passwordEncoder;
35	    private final PasswordValidationService passwordValidationService;
36	    private final AuditLogService auditLogService;
37	
38	    public List<User> listAll() {
39	        return userRepository.findAll();
40	    }
41	
42	    public User findById(Long id) {
43	        return userRepository.findById(id)
44	                .orElseThrow(() -> new IllegalArgumentException("User not found: " + id));
45	    }
46	
47	    public boolean isUsernameAvailable(String username) {
48	        if (username == null || username.isBlank()) return false;
49	        return !userRepository.existsByUsername(username);
50	    }
51	
52	    @Transactional
53	    public User createUser(String username, String password, String fullName, UserRole role,
54	                           String operatorUsername, String ipAddress) {
55	        username = XssInputSanitizer.sanitize(username);
56	        fullName = XssInputSanitizer.sanitize(fullName);
57	        if (username == null || username.isBlank()) {
58	            throw new IllegalArgumentException("Username is required");
59	        }
60	        if (userRepository.existsByUsername(username)) {
61	            throw new IllegalArgumentException("Username already taken: " + username);
62	        }
63	        passwordValidationService.validate(password);
64	
65	        User u = User.builder()
66	                .username(username)
67	                .passwordHash(passwordEncoder.encode(password))
68	                .fullName(fullName)
69	                .role(role)
70	                .active(true)
71	                .build();
72	        User saved = userRepository.save(u);
73	
74	        // AUDIT: never log the password — only username + role.
75	        auditLogService.log(AuditAction.USER_CREATED, "User", saved.getId(),
76	                null, Map.of("username", saved.getUsername(), "role", saved.getRole().name()),
77	                operatorUsername, ipAddress);
78	        return saved;
79	    }
80	
81	    @Transactional
82	    public User updateUser(Long id, String fullName, UserRole role,
83	                           String operatorUsername, String ipAddress) {
84	        User existing = findById(id);
85	        Map<String, Object> before = Map.of(
86	                "fullName", String.valueOf(existing.getFullName()),
87	                "role", existing.getRole().name()
88	        );
89	
90	        boolean roleChanged = existing.getRole() != role;
91	
92	        existing.setFullName(XssInputSanitizer.sanitize(fullName));
93	        existing.setRole(role);
94	        User saved = userRepository.save(existing);
95	
96	        Map<String, Object> after = Map.of(
97	                "fullName", String.valueOf(saved.getFullName()),
98	                "role", saved.getRole().name()
99	        );
100	
101	        auditLogService.log(AuditAction.USER_UPDATED, "User", saved.getId(),
102	                before, after, operatorUsername, ipAddress);
103	        // If the role specifically changed, emit a second high-signal entry.
104	        if (roleChanged) {
105	            auditLogService.log(AuditAction.USER_ROLE_CHANGED, "User", saved.getId(),
106	                    Map.of("role", before.get("role")), Map.of("role", after.get("role")),
107	                    operatorUsername, ipAddress);
108	        }
109	        return saved;
110	    }
111	
112	    @Transactional
113	    public void deactivateUser(Long id, String operatorUsername, String ipAddress) {
114	        User existing = findById(id);
115	        existing.setActive(false);
116	        userRepository.save(existing);
117	        auditLogService.log(AuditAction.USER_DEACTIVATED, "User", id,
118	                Map.of("active", true), Map.of("active", false),
119	                operatorUsername, ipAddress);
120	    }
121	}
