1	package com.meridian.retail.audit;
2	
3	import com.meridian.retail.entity.SensitiveAccessLog;
4	import com.meridian.retail.repository.SensitiveAccessLogRepository;
5	import lombok.RequiredArgsConstructor;
6	import org.springframework.data.domain.Page;
7	import org.springframework.data.domain.Pageable;
8	import org.springframework.stereotype.Service;
9	import org.springframework.transaction.annotation.Propagation;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	/**
13	 * Records access to sensitive fields (e.g. employee notes). Visible only to ADMIN
14	 * via /admin/sensitive-log. Like AuditLogService it writes in REQUIRES_NEW so the
15	 * access is logged even if the surrounding read transaction is rolled back.
16	 */
17	@Service
18	@RequiredArgsConstructor
19	public class SensitiveAccessLogService {
20	
21	    private final SensitiveAccessLogRepository repository;
22	
23	    @Transactional(propagation = Propagation.REQUIRES_NEW)
24	    public void logAccess(String fieldName, String entityType, Long entityId,
25	                          String accessorUsername, String ipAddress) {
26	        repository.save(SensitiveAccessLog.builder()
27	                .fieldName(fieldName)
28	                .entityType(entityType)
29	                .entityId(entityId)
30	                .accessorUsername(accessorUsername)
31	                .ipAddress(ipAddress)
32	                .build());
33	    }
34	
35	    public Page<SensitiveAccessLog> recent(Pageable pageable) {
36	        return repository.findAllByOrderByAccessedAtDesc(pageable);
37	    }
38	}
