11	import org.springframework.http.MediaType;
12	import org.springframework.http.ResponseEntity;
13	import org.springframework.security.access.prepost.PreAuthorize;
14	import org.springframework.security.core.Authentication;
15	import org.springframework.stereotype.Controller;
16	import org.springframework.ui.Model;
17	import org.springframework.web.bind.annotation.GetMapping;
18	import org.springframework.web.bind.annotation.RequestMapping;
19	import org.springframework.web.bind.annotation.RequestParam;
20	import org.springframework.web.servlet.mvc.method.annotation.StreamingResponseBody;
21	
22	import java.time.LocalDateTime;
23	
24	@Controller
25	@RequestMapping("/analytics")
26	@RequiredArgsConstructor
27	public class AnalyticsController {
28	
29	    private final AnalyticsService analyticsService;
30	    private final ExportService exportService;
31	    private final CampaignRepository campaignRepository;
32	    private final CouponRedemptionRepository redemptionRepository;
33	
34	    /** Public-to-staff dashboard. Export button is hidden for non-Finance/Admin via Thymeleaf sec:authorize. */
35	    @GetMapping("/dashboard")
36	    @PreAuthorize("hasAnyRole('FINANCE','ADMIN','OPERATIONS')")
37	    public String dashboard(@RequestParam(required = false) String storeId,
38	                            @RequestParam(required = false) String from,
39	                            @RequestParam(required = false) String to,
40	                            Model model) {
41	        LocalDateTime f = (from == null || from.isBlank()) ? null : LocalDateTime.parse(from + "T00:00:00");
42	        LocalDateTime t = (to == null || to.isBlank())     ? null : LocalDateTime.parse(to + "T23:59:59");
43	
44	        var couponStats = analyticsService.getCouponStats(storeId, f, t);
45	        var discountStats = analyticsService.getDiscountUtilization(f, t);
46	        var top = analyticsService.getTopCampaigns(storeId, f, t, 10);
47	
48	        model.addAttribute("breadcrumb", "Analytics");
49	        model.addAttribute("couponStats", couponStats);
50	        model.addAttribute("discountStats", discountStats);
51	        model.addAttribute("topCampaigns", top);
52	        model.addAttribute("activeCampaigns", campaignRepository.countByStatusAndDeletedAtIsNull(CampaignStatus.ACTIVE));
53	        model.addAttribute("totalRedemptions", redemptionRepository.count());
54	        model.addAttribute("storeId", storeId);
55	        model.addAttribute("fromDate", from);
56	        model.addAttribute("toDate", to);
57	        return "analytics/dashboard";
58	    }
59	
60	    /**
61	     * CSV export — Finance/Admin only.
62	     * RateLimitFilter restricts /analytics/export/** to 10/min/user (60/min for everything else).
63	     */
64	    @GetMapping("/export")
65	    @PreAuthorize("hasAnyRole('FINANCE','ADMIN')")
66	    public ResponseEntity<StreamingResponseBody> exportCsv(Authentication auth, HttpServletRequest request) {
67	        StreamingResponseBody body = exportService.exportRedemptionsCsv(auth.getName(), clientIp(request));
68	        return ResponseEntity.ok()
69	                .contentType(MediaType.parseMediaType("text/csv"))
70	                .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"redemptions.csv\"")
71	                .body(body);
72	    }
73	
74	    private String clientIp(HttpServletRequest request) {
75	        String header = request.getHeader("X-Forwarded-For");
76	        if (header != null && !header.isBlank()) return header.split(",")[0].trim();
77	        return request.getRemoteAddr();
78	    }
