2	
3	import com.meridian.retail.repository.CampaignRepository;
4	import com.meridian.retail.repository.CouponRedemptionRepository;
5	import com.meridian.retail.repository.CouponRepository;
6	import lombok.RequiredArgsConstructor;
7	import org.springframework.stereotype.Service;
8	
9	import java.math.BigDecimal;
10	import java.time.LocalDateTime;
11	import java.util.ArrayList;
12	import java.util.List;
13	import java.util.Optional;
14	
15	/**
16	 * Read-only analytics aggregations for the Finance / Admin dashboard and CSV export.
17	 *
18	 * Every method uses JPQL with named parameters (no string concatenation) so SQL injection
19	 * is structurally impossible.
20	 */
21	@Service
22	@RequiredArgsConstructor
23	public class AnalyticsService {
24	
25	    private final CouponRedemptionRepository redemptionRepository;
26	    private final CouponRepository couponRepository;
27	    private final CampaignRepository campaignRepository;
28	
29	    public record CouponStats(long issuanceCount, long redemptionCount) {}
30	    public record DiscountStats(BigDecimal totalDiscountGiven, BigDecimal avgOrderTotal) {}
31	    public record TopCampaign(Long couponId, String code, long redemptions, BigDecimal totalDiscount) {}
32	
33	    public CouponStats getCouponStats(String storeId, LocalDateTime from, LocalDateTime to) {
34	        long redemptionCount = redemptionRepository.countRedemptions(storeId, from, to);
35	        long issuance = couponRepository.findAll().stream().mapToInt(c -> c.getMaxUses()).sum();
36	        return new CouponStats(issuance, redemptionCount);
37	    }
38	
39	    public DiscountStats getDiscountUtilization(LocalDateTime from, LocalDateTime to) {
40	        BigDecimal total = redemptionRepository.sumDiscountApplied(from, to);
41	        if (total == null) total = BigDecimal.ZERO;
42	        return new DiscountStats(total, BigDecimal.ZERO);
43	    }
44	
45	    public List<TopCampaign> getTopCampaigns(String storeId, LocalDateTime from, LocalDateTime to, int limit) {
46	        List<Object[]> rows = redemptionRepository.topCouponsByRedemptions(storeId, from, to);
47	        List<TopCampaign> out = new ArrayList<>();
48	        int taken = 0;
49	        for (Object[] row : rows) {
50	            if (taken >= limit) break;
51	            Long couponId = ((Number) row[0]).longValue();
52	            long count = ((Number) row[1]).longValue();
53	            BigDecimal sum = (BigDecimal) row[2];
54	            String code = couponRepository.findById(couponId).map(c -> c.getCode()).orElse("?");
55	            out.add(new TopCampaign(couponId, code, count, sum == null ? BigDecimal.ZERO : sum));
56	            taken++;
57	        }
58	        return out;
59	    }
60	}
