13	@Repository
14	public interface CouponRedemptionRepository extends JpaRepository<CouponRedemption, Long> {
15	
16	    @Query("select count(r) from CouponRedemption r where " +
17	           "(:storeId is null or r.storeId = :storeId) and " +
18	           "(:from is null or r.redeemedAt >= :from) and " +
19	           "(:to is null or r.redeemedAt <= :to)")
20	    long countRedemptions(@Param("storeId") String storeId,
21	                          @Param("from") LocalDateTime from,
22	                          @Param("to") LocalDateTime to);
23	
24	    @Query("select coalesce(sum(r.discountApplied), 0) from CouponRedemption r where " +
25	           "(:from is null or r.redeemedAt >= :from) and " +
26	           "(:to is null or r.redeemedAt <= :to)")
27	    BigDecimal sumDiscountApplied(@Param("from") LocalDateTime from,
28	                                  @Param("to") LocalDateTime to);
29	
30	    @Query("select r.storeId, count(r) from CouponRedemption r where " +
31	           "(:from is null or r.redeemedAt >= :from) and " +
32	           "(:to is null or r.redeemedAt <= :to) group by r.storeId")
33	    List<Object[]> redemptionsByStore(@Param("from") LocalDateTime from,
34	                                      @Param("to") LocalDateTime to);
35	
36	    @Query("select r.couponId, count(r), coalesce(sum(r.discountApplied),0) " +
37	           "from CouponRedemption r where " +
38	           "(:storeId is null or r.storeId = :storeId) and " +
39	           "(:from is null or r.redeemedAt >= :from) and " +
40	           "(:to is null or r.redeemedAt <= :to) " +
41	           "group by r.couponId order by count(r) desc")
42	    List<Object[]> topCouponsByRedemptions(@Param("storeId") String storeId,
43	                                           @Param("from") LocalDateTime from,
44	                                           @Param("to") LocalDateTime to);
45	}
