1	package com.meridian.retail.audit;
2	
3	import com.fasterxml.jackson.core.JsonProcessingException;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.meridian.retail.entity.AuditLog;
6	import com.meridian.retail.repository.AuditLogRepository;
7	import lombok.RequiredArgsConstructor;
8	import lombok.extern.slf4j.Slf4j;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Propagation;
11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.time.LocalDateTime;
14	
15	/**
16	 * Immutable audit logger.
17	 *
18	 * REQUIRES_NEW propagation: an audit write must NOT roll back if the surrounding
19	 * business transaction fails — we want to know about attempted operations even
20	 * when they didn't complete. This intentionally creates a separate physical
21	 * transaction for every log() call.
22	 *
23	 * before/after states are serialized to JSON. Plain entities are accepted; pass
24	 * `null` for either side when not applicable (e.g. created has no `before`,
25	 * deleted has no `after`).
26	 *
27	 * The repository this service uses (AuditLogRepository) intentionally does not
28	 * expose any update operation. All access from the rest of the codebase MUST go
29	 * through this service so the audit trail remains tamper-evident.
30	 */
31	@Service
32	@RequiredArgsConstructor
33	@Slf4j
34	public class AuditLogService {
35	
36	    private final AuditLogRepository auditLogRepository;
37	    private final ObjectMapper objectMapper;
38	
39	    @Transactional(propagation = Propagation.REQUIRES_NEW)
40	    public void log(AuditAction action,
41	                    String entityType,
42	                    Long entityId,
43	                    Object before,
44	                    Object after,
45	                    String operatorUsername,
46	                    String ipAddress) {
47	
48	        AuditLog entry = AuditLog.builder()
49	                .action(action.name())
50	                .entityType(entityType)
51	                .entityId(entityId)
52	                .operatorUsername(operatorUsername)
53	                .ipAddress(ipAddress)
54	                .createdAt(LocalDateTime.now())
55	                .beforeState(toJson(before))
56	                .afterState(toJson(after))
57	                .build();
58	        auditLogRepository.save(entry);
59	        log.debug("AUDIT {} {}#{} by {}", action, entityType, entityId, operatorUsername);
60	    }
61	
62	    /** Convenience overload for actions that have no entity context. */
63	    public void log(AuditAction action, String operatorUsername, String ipAddress) {
64	        log(action, null, null, null, null, operatorUsername, ipAddress);
65	    }
66	
67	    private String toJson(Object value) {
68	        if (value == null) return null;
69	        try {
70	            return objectMapper.writeValueAsString(value);
71	        } catch (JsonProcessingException e) {
72	            log.warn("Failed to serialize audit payload: {}", e.getMessage());
73	            return "{\"error\":\"serialization-failed\"}";
74	        }
75	    }
76	}
