1	package com.meridian.retail.security;
2	
3	import io.github.bucket4j.Bandwidth;
4	import io.github.bucket4j.Bucket;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import lombok.extern.slf4j.Slf4j;
10	import org.springframework.beans.factory.annotation.Value;
11	import org.springframework.security.core.Authentication;
12	import org.springframework.security.core.context.SecurityContextHolder;
13	import org.springframework.stereotype.Component;
14	import org.springframework.web.filter.OncePerRequestFilter;
15	
16	import java.io.IOException;
17	import java.time.Duration;
18	import java.util.Map;
19	import java.util.concurrent.ConcurrentHashMap;
20	
21	/**
22	 * Per-user rate limiter using Bucket4j (in-memory token buckets).
23	 *
24	 * SPEC.md:
25	 *   - Standard endpoints: 60 requests/minute per user
26	 *   - Export endpoints (/analytics/export/**): 10 requests/minute per user
27	 *
28	 * This is intentionally a simple in-memory implementation. For a single-tenant on-prem
29	 * deployment that's adequate. The bucket key is "<scope>:<username>" so the standard
30	 * and export quotas are tracked independently.
31	 *
32	 * On exhaustion the filter writes HTTP 429 + Retry-After: 60 and a small JSON body and
33	 * does NOT continue the chain.
34	 */
35	@Component
36	@Slf4j
37	public class RateLimitFilter extends OncePerRequestFilter {
38	
39	    private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();
40	
41	    @Value("${app.rate-limit.standard:60}")
42	    private long standardLimit;
43	
44	    @Value("${app.rate-limit.export:10}")
45	    private long exportLimit;
46	
47	    @Override
48	    protected void doFilterInternal(HttpServletRequest request,
49	                                    HttpServletResponse response,
50	                                    FilterChain chain) throws ServletException, IOException {
51	
52	        // Anonymous traffic is excluded — login attempts have their own IP-based throttling.
53	        String username = currentUsername();
54	        if (username == null) {
55	            chain.doFilter(request, response);
56	            return;
57	        }
58	
59	        boolean isExport = request.getRequestURI().startsWith("/analytics/export");
60	        long capacity = isExport ? exportLimit : standardLimit;
61	        String bucketKey = (isExport ? "export:" : "standard:") + username;
62	
63	        Bucket bucket = buckets.computeIfAbsent(bucketKey, k ->
64	                Bucket.builder()
65	                      .addLimit(Bandwidth.simple(capacity, Duration.ofMinutes(1)))
66	                      .build()
67	        );
68	
69	        if (bucket.tryConsume(1)) {
70	            chain.doFilter(request, response);
71	        } else {
72	            log.warn("Rate limit exceeded for user={} bucket={}", username, bucketKey);
73	            response.setStatus(429);
74	            response.setHeader("Retry-After", "60");
75	            response.setContentType("application/json");
76	            response.getWriter().write(
77	                "{\"error\":\"Rate limit exceeded. Try again in 60 seconds.\"}"
78	            );
79	        }
80	    }
81	
82	    private String currentUsername() {
83	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
84	        if (auth == null || !auth.isAuthenticated() || "anonymousUser".equals(auth.getPrincipal())) {
85	            return null;
86	        }
87	        return auth.getName();
88	    }
89	}
