31	    @BeforeEach
32	    void wireProperties() throws Exception {
33	        Path tmp = Files.createTempDirectory("backup-test");
34	        ReflectionTestUtils.setField(svc, "backupPath", tmp.toString());
35	        ReflectionTestUtils.setField(svc, "retentionDays", 14);
36	        ReflectionTestUtils.setField(svc, "datasourceUrl", "jdbc:mysql://mysql:3306/retail_campaign?useSSL=false");
37	        ReflectionTestUtils.setField(svc, "datasourceUsername", "retail_user");
38	        ReflectionTestUtils.setField(svc, "datasourcePassword", "retail_pass");
39	    }
40	
41	    @Test
42	    void manualBackupAlwaysPersistsRecordAndAudits() {
43	        // mysqldump won't be on PATH inside this unit test JVM — that's expected.
44	        // The service still saves a BackupRecord with status FAILED so the trail exists.
45	        when(backupRecordRepository.save(any(BackupRecord.class))).thenAnswer(inv -> {
46	            BackupRecord r = inv.getArgument(0);
47	            r.setId(1L);
48	            return r;
49	        });
50	        when(backupRecordRepository.findByStatusAndCreatedAtBefore(any(BackupStatus.class), any()))
51	                .thenReturn(List.of());
52	
53	        BackupRecord r = svc.runManualBackup("admin", "127.0.0.1");
54	        assertThat(r).isNotNull();
55	        // Either COMPLETE (if mysqldump happened to exist) or FAILED — both are valid persisted outcomes
56	        assertThat(r.getStatus()).isIn(BackupStatus.COMPLETE, BackupStatus.FAILED);
57	        assertThat(r.getFilename()).isNotBlank();
